function LModelManager:Initialize()
	LxBaseMgr.Initialize(self)

	self._modelList = nil					-- 所有数据模块列表
	self._isAllModelInited = false			-- 是否所有模块数据请求完毕
	self._curInitModelName = "undefined"	-- 当前正在请求数据的模块名称
	self._modelInitTimer = nil				-- 所有模块初始化超时定时器
	self._initTimes = 0                    --初始化次数

	self:AddEventHandler(EventNames.LOGIN_ACCOUNT_OK, function(...) self:OnLoginAccountOk(...) end)
end

function LModelManager:Destroy()
	self:ClearModelInitTimer()
	self:DestroyAllModels()
	LxBaseMgr.Destroy(self)
end

function LModelManager:CreateAllModels()
	if not self._modelList then
		self._modelList = LXFW.LxKVList:New()
		for k,v in ipairs(LModelManager.ModelList) do
			self:CreateModel(v)
		end
		if CS.IsWebGL() then
			gLGpManager:InitStartManager()
		end
	end
end

-- 角色登录成功，开始逐个请求模块数据
function LModelManager:OnLoginAccountOk()
	self:CreateAllModels()

	self:ClearAllModels()

	if self._initTimes and self._initTimes > 0 then
		GF.StartWait(nil,"重连中...")
	end
	self:InitAllModels()
end

-- 清除定时器
function LModelManager:ClearModelInitTimer()
	local modelInitTimer = self._modelInitTimer
	if (modelInitTimer) then
		LxTimer.DelayTimeStop(modelInitTimer)
		self._modelInitTimer = nil
	end
end

-- 设置定时器
function LModelManager:SetModelInitTimer()
	self:ClearModelInitTimer()
	self._modelInitTimer = LxTimer.DelayTimeCall(function() self:OnModelInitTimeOut() end, LModelManager.MODEL_INIT_WAIT_SEC)
end

-- 模块初始化超时
function LModelManager:OnModelInitTimeOut()
	self:ClearModelInitTimer()
	MgrCenter.NetworkMgr:StopConnect("ModelInit TimeOut | " .. self._curInitModelName .. "\n")
end

-- 销毁所有模块数据
function LModelManager:DestroyAllModels()
	local modelList = self._modelList
	if not modelList then
		return
	end
	for k,v in ipairs(modelList:GetValueList()) do
		v:ModelDestroy()
	end
	self._isAllModelInited = false
end

-- 清除所有模块数据
function LModelManager:ClearAllModels()
	local modelList = self._modelList
	if not modelList then
		return
	end
	for k,v in ipairs(modelList:GetValueList()) do
		v:ModelClear()
	end
	self._isAllModelInited = false
end

-- 按顺序逐个模块请求数据
function LModelManager:InitAllModels()
	local isAllModelInited = self._isAllModelInited
	if (isAllModelInited) then
		return
	end

	local modelList = self._modelList
	for k,v in ipairs(modelList:GetValueList()) do
		v:ModelInit()
	end

	self:DoEnumModelInit(1)
end

-- 根据列表位置执行对应模块数据请求, 执行到末尾表示所有模块请求完成
function LModelManager:DoEnumModelInit(pos)
	local modelList = self._modelList
	local cnt = modelList:GetSize()
	if (cnt >= pos) then
		local model = modelList:GetAt(pos)
		self._curInitModelName = model:GetModelName()
		model:ModelClear()
		self:SetModelInitTimer()

		model:ModelRequest()
		self:ClearModelInitTimer()
	else
		self:OnLoginModelFinishAll()
	end
end

-- 每个模块请求完成的递归回调
function LModelManager:OnModelFinish(model)
	local modelList = self._modelList
	local pos = modelList:GetIndexByKey(model:GetModelName())
	self:DoEnumModelInit(pos+1)
end

-- 创建一个新模块
-- 设置全局访问变量 (e.g. gModelTemplate)
function LModelManager:CreateModel(modelName)
	local modelClass = LxRequire("LApp.Models.Model." .. modelName)
	if not modelClass then
		LogError("LModelManager:CreateModel not exist! modelName="..tostring(modelName))
		return
	end
	local model = modelClass:New()
	model:SetModelName(modelName)
	model:ModelCreate()
	self._modelList:Add(modelName, model)
	BaseG[model:GetInstanceName()] = model
end

-- 所有模块数据请求完成的回调
function LModelManager:OnLoginModelFinishAll()
	GF.StopWait()
	local modelList = self._modelList
	local cnt = modelList:GetSize()
	self._isAllModelInited = true
	self._initTimes = (self._initTimes or 0 )+ 1


	LXFW.LxLog.LOGIN("LOGIN_MODEL_OK\n")
	FireEvent(EventNames.LOGIN_MODEL_OK, cnt)
end

return LModelManager